const response = msg.payload;

if (!response || !response.data) {
    node.warn('No data received from investing.com');
    return null;
}

const data = response.data;
const now = new Date();

const parsed = {
    symbol: 'NQ100',
    price: parseFloat(data.last) || parseFloat(data.price),
    change_value: parseFloat(data.change) || 0,
    change_percent: parseFloat(data.change_percent) || parseFloat(data.changePercent) || 0,
    volume: parseInt(data.volume) || 0,
    open_price: parseFloat(data.open) || 0,
    high_price: parseFloat(data.high) || 0,
    low_price: parseFloat(data.low) || 0,
    close_price: parseFloat(data.close) || 0,
    timestamp: now.toISOString(),
    source: 'investing_com'
};

node.status({ text: `Price: ${parsed.price}, Change: ${parsed.change_percent}%` });

return { payload: parsed };

if (msg.payload.statusCode && msg.payload.statusCode !== 200) {
    node.error('HTTP Error: ' + msg.payload.statusCode + ' - ' + msg.payload.statusMessage);
    // Log failed attempt
    const errorLog = {
        timestamp: new Date().toISOString(),
        source: 'investing_scraper',
        error: msg.payload.statusCode,
        url: msg.url
    };
    node.warn(JSON.stringify(errorLog));
}
return null;

const now = new Date();
const hour = now.getUTCHours();

// US market hours: 14:30 - 21:00 UTC (9:30 AM - 4:00 PM EST)
const isMarketHours = (hour >= 14 && hour < 21);

if (!isMarketHours) {
    node.status({ text: 'Outside market hours - skipping', fill: 'grey', shape: 'ring' });
    return null;
}

return msg;

// Absolute Score Calculation
// Weights: nq200ma(30%), nq50ma(30%), nq20ema50ema(20%), mtf(10%), market_phase(10%)

const weights = {
    nq200ma: 0.30,
    nq50ma: 0.30,
    nq20ema50ema: 0.20,
    mtf: 0.10,
    market_phase: 0.10
};

// Default scores if no data (neutral = 50)
let nq200maScore = 50;
let nq50maScore = 50;
let nq20ema50emaScore = 50;
let mtfScore = 50;
let marketPhaseScore = 50;

if (msg.payload && msg.payload.length > 0) {
    const data = msg.payload[0];

    // Calculate NQ200MA score (price vs 200MA)
    // Score = 100 if price > 200MA, 0 if price < 200MA * 0.9, linear between
    if (data.price && data.ma200) {
        const ratio = data.price / data.ma200;
        nq200maScore = Math.min(100, Math.max(0, (ratio - 0.9) * 1000));
    }

    // Calculate NQ50MA score
    if (data.price && data.ma50) {
        const ratio = data.price / data.ma50;
        nq50maScore = Math.min(100, Math.max(0, (ratio - 0.9) * 1000));
    }

    // Calculate NQ20EMA vs NQ50EMA score
    if (data.ema20 && data.ema50) {
        nq20ema50emaScore = data.ema20 > data.ema50 ? 100 : 0;
    }

    // MTF score from data
    if (data.mtf_score !== undefined) {
        mtfScore = data.mtf_score;
    }

    // Market phase score
    if (data.market_phase !== undefined) {
        const phaseScores = { accumulation: 100, markup: 80, distribution: 20, markdown: 0 };
        marketPhaseScore = phaseScores[data.market_phase] || 50;
    }
}

// Calculate final weighted score
const finalScore = Math.round(
    nq200maScore * weights.nq200ma +
    nq50maScore * weights.nq50ma +
    nq20ema50emaScore * weights.nq20ema50ema +
    mtfScore * weights.mtf +
    marketPhaseScore * weights.market_phase
);

// Determine trend direction
let trendDirection = 'sideways';
if (finalScore >= 80) trendDirection = 'strong_bull';
else if (finalScore >= 60) trendDirection = 'bull';
else if (finalScore >= 40) trendDirection = 'weak';
else if (finalScore >= 20) trendDirection = 'bear';
else trendDirection = 'strong_bear';

msg.payload = {
    nq200ma_score: Math.round(nq200maScore),
    nq50ma_score: Math.round(nq50maScore),
    nq20ema50ema_score: Math.round(nq20ema50emaScore),
    mtf_score: Math.round(mtfScore),
    market_phase_score: Math.round(marketPhaseScore),
    final_absolute_score: finalScore,
    trend_direction: trendDirection,
    timestamp: new Date()
};

return msg;

// Reference Score Calculation
// Weights: components_breadth(20%), components_risk(10%), technical_rsi(15%), technical_atr(10%), technical_zscore(10%), technical_macd(5%), technical_divergence(5%), money_flow_futures(15%), money_flow_etf(10%)

const weights = {
    components_breadth: 0.20,
    components_risk: 0.10,
    technical_rsi: 0.15,
    technical_atr: 0.10,
    technical_zscore: 0.10,
    technical_macd: 0.05,
    technical_divergence: 0.05,
    money_flow_futures: 0.15,
    money_flow_etf: 0.10
};

// Default scores if no data (neutral = 50)
let componentsBreadthScore = 50;
let componentsRiskScore = 50;
let technicalRsiScore = 50;
let technicalAtrScore = 50;
let technicalZscoreScore = 50;
let technicalMacdScore = 50;
let technicalDivergenceScore = 50;
let moneyFlowFuturesScore = 50;
let moneyFlowEtfScore = 50;

if (msg.payload && msg.payload.length > 0) {
    const data = msg.payload[0];

    // Components: Breadth (percentage of stocks above moving average)
    if (data.components_breadth !== undefined) {
        componentsBreadthScore = Math.min(100, Math.max(0, data.components_breadth));
    }

    // Components: Risk score
    if (data.components_risk !== undefined) {
        componentsRiskScore = 100 - Math.min(100, Math.max(0, data.components_risk));
    }

    // Technical: RSI (30-70 neutral, above 70 = overbought, below 30 = oversold)
    if (data.rsi !== undefined) {
        if (data.rsi >= 70) technicalRsiScore = 100;
        else if (data.rsi <= 30) technicalRsiScore = 0;
        else technicalRsiScore = ((data.rsi - 30) / 40) * 100;
    }

    // Technical: ATR (normalize to 0-100, lower is better for trend)
    if (data.atr_percent !== undefined) {
        technicalAtrScore = Math.min(100, Math.max(0, 100 - (data.atr_percent * 10)));
    }

    // Technical: Z-Score (-2 to +2 normalized to 0-100)
    if (data.zscore !== undefined) {
        technicalZscoreScore = ((data.zscore + 2) / 4) * 100;
        technicalZscoreScore = Math.min(100, Math.max(0, technicalZscoreScore));
    }

    // Technical: MACD (positive histogram = bullish)
    if (data.macd_histogram !== undefined) {
        technicalMacdScore = data.macd_histogram > 0 ? 50 + (Math.min(50, data.macd_histogram * 100)) : 50 + (Math.max(-50, data.macd_histogram * 100));
    }

    // Technical: Divergence (price vs indicator)
    if (data.divergence !== undefined) {
        const divergenceScores = { bullish: 100, neutral: 50, bearish: 0 };
        technicalDivergenceScore = divergenceScores[data.divergence] || 50;
    }

    // Money Flow: Futures (NQ futures position change)
    if (data.futures_oi_change !== undefined) {
        moneyFlowFuturesScore = Math.min(100, Math.max(0, 50 + data.futures_oi_change * 10));
    }

    // Money Flow: ETF (TQQQ/QQQ inflow)
    if (data.etf_inflow !== undefined) {
        moneyFlowEtfScore = Math.min(100, Math.max(0, 50 + data.etf_inflow * 10));
    }
}

// Calculate final weighted score
const finalScore = Math.round(
    componentsBreadthScore * weights.components_breadth +
    componentsRiskScore * weights.components_risk +
    technicalRsiScore * weights.technical_rsi +
    technicalAtrScore * weights.technical_atr +
    technicalZscoreScore * weights.technical_zscore +
    technicalMacdScore * weights.technical_macd +
    technicalDivergenceScore * weights.technical_divergence +
    moneyFlowFuturesScore * weights.money_flow_futures +
    moneyFlowEtfScore * weights.money_flow_etf
);

msg.payload = {
    components_breadth_score: Math.round(componentsBreadthScore),
    components_risk_score: Math.round(componentsRiskScore),
    technical_rsi_score: Math.round(technicalRsiScore),
    technical_atr_score: Math.round(technicalAtrScore),
    technical_zscore_score: Math.round(technicalZscoreScore),
    technical_macd_score: Math.round(technicalMacdScore),
    technical_divergence_score: Math.round(technicalDivergenceScore),
    money_flow_futures_score: Math.round(moneyFlowFuturesScore),
    money_flow_etf_score: Math.round(moneyFlowEtfScore),
    final_reference_score: finalScore,
    timestamp: new Date()
};

return msg;

let futu = global.get('futuClient');
if (!futu || !futu.connected) {
    global.set('futuNeedConnect', true);
    return { payload: { action: 'connect' } };
}
global.set('futuNeedConnect', false);
return { payload: { action: 'subscribe', symbols: ['MNQ'] } };

const data = msg.payload;

// Handle different message types from Futu OpenD
if (data.type === 'quote' && data.symbol === 'MNQ') {
    const parsed = {
        symbol: 'MNQ',
        price: data.last || data.price,
        open_price: data.open,
        high_price: data.high,
        low_price: data.low,
        volume: data.volume || data.vol,
        turnover: data.turnover,
        open_interest: data.openInterest || data.oi,
        bid_price: data.bid1,
        ask_price: data.ask1,
        bid_volume: data.bidVol1,
        ask_volume: data.askVol1,
        timestamp: new Date(data.time || Date.now()).toISOString(),
        source: 'futu_opend',
        data_type: 'tick',
        metadata: JSON.stringify({
            security_type: data.securityType,
            exchange: data.exchange,
            lot_size: data.lotSize
        })
    };
    return { payload: parsed };
}

return null;

if (msg.payload.error) {
    node.error('Futu OpenD Error: ' + msg.payload.error);
    // Attempt reconnection after error
    setTimeout(() => {
        global.set('futuNeedConnect', true);
    }, 5000);
}
return null;
